import base64, json, hmac, hashlib, requests

def b64u(x):
    return base64.urlsafe_b64encode(x).rstrip(b'=').decode()

def jwt_hs256(payload, secret):
    header={'alg':'HS256','typ':'JWT'}
    s=b64u(json.dumps(header,separators=(',',':')).encode())+'.'+b64u(json.dumps(payload,separators=(',',':')).encode())
    sig=hmac.new(secret.encode(), s.encode(), hashlib.sha256).digest()
    return s+'.'+b64u(sig)

